def get_sector_name(sector_code: str) -> str:
    """
    根據產業代號獲取產業名稱
    
    Parameters:
    -----------
    sector_code : str
        產業代號 (如 '01', '16', '31')
    
    Returns:
    --------
    str : 產業名稱
    """
    sector_map = {
        '01': '水泥工業',
        '02': '食品工業',
        '03': '塑膠工業',
        '04': '紡織纖維',
        '05': '電機機械',
        '06': '電器電纜',
        '07': '化學生物醫療',
        '08': '鋼鐵工業',
        '09': '橡膠工業',
        '10': '建材營造',
        '11': '造紙工業',
        '12': '航運業',
        '13': '汽車工業',
        '14': '其他運輸工具',
        '15': '電子零組件',
        '16': '電子工業',
        '17': '資訊服務業',
        '18': '其他電子業',
        '19': '建材營造 (二類)',
        '20': '貿易百貨',
        '21': '油電燃氣業',
        '22': '綜合',
        '23': '金融保險業',
        '24': '觀光事業',
        '25': '金融業 (二類)',
        '26': '投資控股',
        '27': '其他',
        '28': '光電業',
        '29': '電腦及週邊設備業',
        '30': '通訊網路業',
        '31': '半導體業',
        '32': '電子零組件業 (二類)',
        '33': '電子通路業',
        '34': '資訊服務業 (二類)',
        '35': '其他電子業 (二類)',
    }
    return sector_map.get(sector_code, f'產業{sector_code}')


